"""
MKT Original Commentary — 1 Chronicles chapters 9–10
Run: python3 scripts/zc-original-1chronicles-9-10.py

Ch 9: Post-exilic settler list; Levitical gatekeeper installation; Saul genealogy (repeat of ch 8)
Ch 10: Saul's death at Gilboa; Chronicler's theological verdict

Key decisions:
- yithyaḥes (9:1): Hithpael reflexive — the community enrolled itself; important for Chronicler's
  theology of self-identification with the covenant people
- nĕtînîm (9:2): "given ones" — note the passive form encoding a category of temple service
- David and Samuel the rōʾeh (9:22): title distinction hārōʾeh vs. hannāḇîʾ in the Chronicler
- maʿal (10:13): the Chronicler's signature term for covenant treachery; appears 24× in Chronicles vs.
  only 3× in Samuel-Kings; this is the interpretive lens through which the entire Saul narrative is read
- dāraš (10:14): seeking/inquiring of YHWH — the Chronicler's evaluative criterion;
  Saul is condemned for not doing what the Chronicler will praise David for
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ORIGINAL = {
  "9": {
    "1": "<p><strong><em>wᵉyithyaḥasû</em></strong> — the verb <em>yāḥas</em> (to be enrolled/registered by genealogy) appears in the Hithpael reflexive here: <em>wayyithyaḥasû kol yiśrāʾēl</em>, &lsquo;and all Israel enrolled themselves.&rsquo; The Hithpael signals community self-identification — the act of registering in the genealogies is active, not merely assigned. <strong><em>sēper malkê yiśrāʾēl</em></strong> — &lsquo;the book of the kings of Israel&rsquo; is the Chronicler&rsquo;s most frequently cited source (appearing with variations throughout 1–2 Chronicles); it is distinct from canonical Kings. <strong><em>bᵉmaʿalām</em></strong> — &lsquo;because of their unfaithfulness&rsquo; (Qal infinitive construct of <em>māʿal</em>); this word will recur as the Chronicler&rsquo;s verdict on Saul in 10:13 — the exile of Judah and the death of Saul are both attributed to the same word-root, binding national history to royal failure under one interpretive category.</p>",
    "2": "<p><strong><em>nᵉtînîm</em></strong> — &lsquo;temple servants,&rsquo; literally &lsquo;the given ones&rsquo; (Qal passive participle of <em>nātan</em>, to give). The form encodes the category: persons given over to temple service, likely descendants of captives assigned as support staff for the Levites (Num 31:47; Josh 9:27; Ezra 2:43-54). The term occurs 17× in Ezra-Nehemiah and 2× in Chronicles, marking a service class whose origins predate the exile but whose community identity is reconstituted in the post-exilic settlement. The listing of Israelites, priests, Levites, and Nethinim as four distinct groups reflects the Chronicler&rsquo;s consistently stratified view of the worshipping community.</p>",
    "3": "<p>The enumeration of settlers from Judah, Benjamin, Ephraim, and Manasseh in Jerusalem is theologically significant: Chronicles includes northern-tribe representation in the restored Jerusalem community. Samuel-Kings largely writes off the north after the 722 BCE Assyrian deportation; the Chronicler envisions a reunified Israel around the Davidic-Levitical center. The grammatical structure is a simple listing with <em>wayyēšᵉḇû</em> (waw-consecutive Qal imperfect of <em>yāšaḇ</em>, &lsquo;to settle/dwell&rsquo;) — the narrative past tense marking the settlement as a completed, definitive act.</p>",
    "4": "<p>A genealogical line from Perez son of Judah through five patronymic links to Uthai — the <em>ben</em>-chain establishes legitimacy of settlement for the post-exilic community. The Perez lineage is the Davidic sub-clan (Ruth 4:18-22; 1 Chr 2:4-15), giving this first settler special prestige. No linguistic variants from the parallel in Neh 11:4.</p>",
    "5": "<p><strong><em>šîlōnî</em></strong> — the &lsquo;Shilonites&rsquo; are descendants of Shelah son of Judah (1 Chr 2:3; Num 26:20), not Shiloh the city. The designation <em>habbe̊kôr</em> (&lsquo;the firstborn&rsquo;) applied to Asaiah signals priority of standing within this clan.</p>",
    "6": "<p><strong><em>bᵉnê zeraḥ</em></strong> — the Zerahite sub-clan of Judah (Zerah son of Judah, twin of Perez); Jeuel and kinsmen totaling 690. The Zerahites are the lineage of Achan/Achar (2:6-7), but here they appear as legitimate settlers — the genealogy includes even the troubled line.</p>",
    "7": "<p>Benjaminite genealogical line to Sallu: <em>meshullām ben hōḏawyāh ben hassᵉnûʾāh</em> — three patronymic links. Parallel in Neh 11:7 has slight variations (<em>mᵉšullam ben yôʿēd ben pᵉdāʾyāh ben qôlāʾyāh ben maʿaśēyāh ben ʾîṯîʾēl ben yᵉšaʿyāh</em>), suggesting either different individuals or textual variants in the transmission. The Chronicler&rsquo;s shorter list may preserve an earlier form.</p>",
    "8": "<p>Three more Benjaminite settlers listed with genealogical depth: Ibneiah through Jeroham; Elah through Uzzi and Michri; Meshullam through a longer chain including Shephatiah, Reuel, and Ibnijah. The variety of lineage depths (one, two, four links) reflects varying completeness in the source registers rather than editorial inconsistency.</p>",
    "9": "<p><strong><em>ʾālpayim šᵉlōšâ wᵉḥāmišîm wᵉtišʿāh</em></strong> — 956 Benjaminite heads of ancestral households. The summary phrase <em>kol ʾēlleh ʾănāšîm rāʾšê ʾāḇôt</em> (&lsquo;all these were heads of ancestral households&rsquo;) closes the genealogical unit with its standard conclusion formula, marking completeness of the register.</p>",
    "10": "<p>The priestly roster begins with three names — Jedaiah, Jehoiarib, Jachin — without full genealogical chains. Jedaiah and Jehoiarib are the two most prominent priestly families in the post-exilic period (Neh 12:6; 1 Chr 24:7); Jehoiarib heads the first of the 24 priestly divisions (24:7). The brevity of this entry contrasts with the depth of Azariah&rsquo;s genealogy in v11.</p>",
    "11": "<p><strong><em>nāgîd bêt hāʾĕlōhîm</em></strong> — Azariah is identified as &lsquo;the chief officer (nāgîd) of the house of God.&rsquo; The term <em>nāgîd</em> (leader, ruler, prince) is the Chronicler&rsquo;s preferred title for the highest-ranking temple official — the same word used of David as YHWH&rsquo;s designated king (1 Chr 17:7). The long genealogical chain (six links back to Zadok) establishes Azariah&rsquo;s Zadokite legitimacy — the Zadokite priesthood had the exclusive claim to temple service in the Chronicler&rsquo;s (and Ezekiel&rsquo;s) theology (Ezek 40:46; 44:15).</p>",
    "12": "<p>Adaiah son of Jeroham with four links; Maasai son of Adiel with three links. The genealogical variety and different chain lengths likely reflects different source documents with varying levels of completeness. The Neh 11:12-14 parallel preserves different versions of some of these names.</p>",
    "13": "<p><strong><em>gibbôrê ḥayil mᵉlāʾḵat bêt hāʾĕlōhîm</em></strong> — &lsquo;capable men for the service/work of the house of God.&rsquo; The phrase <em>gibbôrê ḥayil</em> (men of valor/capable men) is usually military terminology (Judg 11:1; 1 Sam 16:18); its application to priestly service here underscores that temple work is treated with the same gravity as military service. Total: 1,760 — a substantial priestly corps for the restored community.</p>",
    "14": "<p>The Levitical roster opens with Shemaiah son of Hasshub through to Hashabiah — assigned from the sons of Merari. The three Levitical clans (Gershon, Kohath, Merari) each provide settlers; Merari appears first here, which the Chronicler likely follows from his source registers without editorial significance.</p>",
    "15": "<p>Four Levites listed: Bakbakkar, Heresh, Galal, and Mattaniah — the last with a four-link chain through Micah and Zichri to Asaph. Asaph is one of the three great Levitical music guilds (with Heman and Jeduthun/Ethan); the Asaphite line is particularly prominent in Chronicles and in Psalm superscriptions.</p>",
    "16": "<p>Obadiah son of Shemaiah through Galal to Jeduthun — another guild connection (Jeduthun/Ethan is the third guild founder). Berechiah son of Asa son of Elkanah — note <em>ʾĕlqānāh</em>, the name also borne by Samuel&rsquo;s father (1 Sam 1:1), situating this Levite in the same tribal and vocational stream. Their residence in <em>ḥaṣrê nᵉṭôpātî</em> (&lsquo;the villages of the Netophathites&rsquo;) reflects the Levitical settlement pattern in Judahite towns (Neh 12:28).</p>",
    "17": "<p><strong><em>šōʿᵃrîm</em></strong> — &lsquo;gatekeepers,&rsquo; literally &lsquo;those who keep the gate&rsquo; (participle of <em>šāʿar</em>). The four names — Shallum, Akkub, Talmon, Ahiman — with their kinsmen form the core gatekeeper corps. <strong><em>rōʾš</em></strong> — Shallum is &lsquo;the chief&rsquo; (head) of the gatekeepers; the same title will reappear in v26 for the four &lsquo;chief gatekeepers&rsquo; (<em>hāšōʿᵃrîm lāʾarbaʿ</em>). The Chronicler devotes more attention to the gatekeepers than any other biblical source, reflecting their post-exilic institutional importance.</p>",
    "18": "<p><strong><em>šaʿar hammelek qēḏmāh</em></strong> — &lsquo;the king&rsquo;s gate to the east.&rsquo; The Eastern Gate was the primary royal access to the temple mount; &lsquo;formerly&rsquo; (<em>ʿad hēnnāh</em>, literally &lsquo;until now&rsquo; or &lsquo;up to this point&rsquo;) signals continuity from the pre-exilic gatekeeper establishment into the post-exilic restoration — the same families, at the same gates. <strong><em>maḥᵃnôt bᵉnê lēwî</em></strong> — &lsquo;the Levitical camps&rsquo;: the wilderness camp arrangement (Num 2:17; 3:21-38) is invoked to establish the Levitical gatekeeping tradition as Mosaic in origin.</p>",
    "19": "<p><strong><em>šōmᵉrê sippôt hāʾōhel</em></strong> — &lsquo;guardians of the thresholds of the tent.&rsquo; The word <em>sap</em>/<em>sippāh</em> (threshold, doorstep) is used of the temple threshold with particular solemnity (Ezek 9:3; 10:4); it is the boundary between the holy and the profane. The Korahites are specifically identified: Shallum son of Kore son of Ebiasaph son of Korah — the same lineage as Ps 84:10 (&lsquo;I would rather be a doorkeeper in the house of my God than dwell in the tents of wickedness&rsquo;), where the Korahite authorship of the Psalms of Korah is itself a statement of Korahite identity as threshold-servants. The phrase <em>kaʾăḇôtêhem</em> (&lsquo;as their fathers had been&rsquo;) is the key word: gatekeeping is inherited priestly vocation, not appointment.</p>",
    "20": "<p><strong><em>pînᵉḥās ben ʾelʿāzār nāgîd ʿălêhem lᵉpānîm</em></strong> — &lsquo;Phinehas son of Eleazar was formerly their chief/leader&rsquo; (<em>nāgîd</em>, the same term used for temple leaders in v11). The additional phrase <strong><em>YHWH ʿimmô</em></strong> — &lsquo;and YHWH was with him&rsquo; — is the highest approbation formula in the Deuteronomistic and Chronicler&rsquo;s vocabulary (used of Joshua, David, and Solomon with the same language); it validates the entire Korahite gatekeeper tradition by anchoring it to the most celebrated priestly act in Israelite history (Phinehas&rsquo;s zeal at Peor, Num 25:7-13; Ps 106:30-31).</p>",
    "21": "<p>Zechariah son of Meshelemiah at the entrance of the <em>ʾōhel môʿēd</em> — &lsquo;the tent of meeting,&rsquo; the technical term for the wilderness tabernacle. The use of this archaic designation (rather than &lsquo;house of God&rsquo;) situates the post-exilic gatekeeper function within the continuous trajectory from wilderness to temple — a characteristic Chronicler rhetorical move. This Zechariah will appear again as one of the lead gatekeepers in 1 Chr 26:2,14.</p>",
    "22": "<p><strong><em>mithyaḥᵃsîm</em></strong> — &lsquo;enrolled in their genealogical records,&rsquo; the same Hithpael of <em>yāḥas</em> as v1 — the chapter is framed by the verb of genealogical self-enrollment. Total: 212. <strong><em>dāwid wîšᵉmûʾēl hārōʾeh</em></strong> — &lsquo;David and Samuel the <em>rōʾeh</em> (seer) established them.&rsquo; The title <em>rōʾeh</em> (seer, from <em>rāʾāh</em>, to see) is the archaic term for a prophet (1 Sam 9:9 explicitly glosses it: &lsquo;the one now called a prophet was formerly called a seer&rsquo;). The Chronicler designates Samuel as <em>hārōʾeh</em> — not <em>hannāḇîʾ</em> — preserving the older title; Samuel&rsquo;s own books use both. The claim that David and Samuel jointly &lsquo;established&rsquo; (<em>yissᵉdûm</em>, Piel of <em>yāsaḏ</em>, to found/establish) the gatekeeping posts roots the institution in the two figures who stand at the hinge of Israelite history.</p>",
    "23": "<p><strong><em>šaʿarê bêt YHWH lᵉbêt hāʾōhel</em></strong> — &lsquo;the gates of the house of YHWH — the house of the tent.&rsquo; The phrase apposits the Solomonic temple (&lsquo;house of YHWH&rsquo;) with the wilderness tabernacle (&lsquo;the tent&rsquo;) — the Chronicler&rsquo;s standard collapsing of temporal distance between the two sanctuaries to assert continuity. <em>lᵉmišmārôt</em> (by guard-stations, by rotations) is the organization principle for all temple service in Chronicles (see 1 Chr 24-26).</p>",
    "24": "<p>Gatekeepers at the four compass points: <em>mизrāḥ yāmāh ṣāpôn negeḇ</em> — east, west, north, south. The four-direction scheme places YHWH&rsquo;s house at the cosmological center. The gatekeeper arrangement mirrors the tribal encampment around the tabernacle (Num 2), where each direction had its assigned tribes — the temple is the wilderness sanctuary translated into permanent architecture.</p>",
    "25": "<p><strong><em>ʾaḥêhem</em></strong> — &lsquo;their fellow Levites&rsquo; in villages came to serve <em>šiḇʿat hayyāmîm</em> — &lsquo;every seven days.&rsquo; The seven-day rotation for the subsidiary gatekeepers from surrounding villages reflects the same principle as the priestly divisions (24 courses, each serving one week twice per year). The verb <em>yāḇôʾû</em> (Qal imperfect, iterative sense) marks repeated action — this is the ongoing pattern of temple staffing.</p>",
    "26": "<p><strong><em>gᵉḇîrîm</em></strong> — &lsquo;the four chief gatekeepers were entrusted.&rsquo; The word <em>gᵉḇîrîm</em> (great men, men of strength) indicates status within the gatekeeper corps. <strong><em>bāṭûaḥ</em></strong> — &lsquo;entrusted&rsquo; (Qal passive participle of <em>bāṭaḥ</em>, to trust/rely); the entrusting of the storerooms and treasuries to the chief gatekeepers reflects an institutional trust-arrangement with formal accountability.</p>",
    "27": "<p><strong><em>wayyālînû</em></strong> — &lsquo;they lodged the night around the house of God&rsquo; (Qal imperfect, narrative past). The Levitical night-watch at the temple is attested in Ps 134:1 (&lsquo;all you servants of YHWH who stand in the house of YHWH by night&rsquo;) — a Korahite psalm likely connected to this gatekeeping institution. <strong><em>ûlāhem miftaḥ</em></strong> — &lsquo;to them belonged the opening&rsquo; of the temple every morning; the gatekeepers had exclusive custody of the keys and the first access — and the accountability.</p>",
    "28": "<p><strong><em>wᵉqāṣṯ mēhem ʿal kᵉlê hāʿăḇōḏāh</em></strong> — &lsquo;Some of them were over the vessels of service.&rsquo; The detailed accounting system — vessels counted in and out (<em>bᵉmispār yᵉḇîʾûm ûbᵉmispār yôṣîʾûm</em>) — reflects the stringent temple accountability recorded in Ezra 1:9-11, where Cyrus&rsquo;s vessels are inventoried precisely. The Chronicler&rsquo;s interest in temple vessels as sacred objects requiring careful custody appears repeatedly (1 Chr 28:13-14; 2 Chr 36:7).</p>",
    "29": "<p>The category of those appointed over furnishings and holy vessels (<em>kᵉlê haqqōḏeš</em>) includes oversight of fine flour, wine, oil, incense, and aromatic spices — all the consumable elements of the daily grain offerings, wine libations, and incense. The Levitical management of these commodities reflects a developed temple economy requiring specialized knowledge of ritual quantities and purity standards.</p>",
    "30": "<p><strong><em>wûmin bᵉnê hakkōhᵃnîm</em></strong> — &lsquo;from among the sons of the priests&rsquo; some prepared the spice blend (<em>mirsaḥat habbe̊šāmîm</em>). The spice/incense preparation was specifically a priestly — not Levitical — task; Exod 30:34-38 prescribes the incense formula and prohibits its preparation or use by anyone other than priests for the altar. This verse marks the boundary between Levitical and priestly administrative domains.</p>",
    "31": "<p><strong><em>ʾemûnāh</em></strong> — &lsquo;trusted responsibility&rsquo; or &lsquo;faithfulness&rsquo; (from <em>ʾāman</em>, to be firm, faithful). Mattithiah&rsquo;s role over the flat cakes (<em>maḥᵃḇattôt</em>) is described as <em>bᵉʾemûnāh</em> — with faithfulness, in a position of trust. The Chronicler&rsquo;s emphasis on institutional faithfulness (<em>ʾemûnāh</em>) in temple service reflects the same value that Hezekiah will apply to his treasury oversight (2 Chr 31:12,15,18) — the temple economy requires moral as well as ritual fidelity.</p>",
    "32": "<p>The Kohathite kinsmen responsible for the rows of bread (<em>leḥem hammaʿărāḵet</em>, &lsquo;showbread,&rsquo; literally &lsquo;bread of the arrangement/rows&rsquo;) — the twelve loaves set out before YHWH each Sabbath (Lev 24:5-9). The twice-weekly change of showbread required careful preparation; this verse identifies a specific Kohathite sub-family holding hereditary responsibility for it.</p>",
    "33": "<p><strong><em>hāmᵉšōrᵉrîm rāʾšê ʾāḇôt halᵉwiyyîm</em></strong> — &lsquo;These are the singers, heads of Levitical clans.&rsquo; <strong><em>pᵉtûrîm ʿal kol ʾăḇōḏāh</em></strong> — &lsquo;exempt from all other service.&rsquo; The word <em>pāṭar</em> (to release, exempt) is relatively rare; the singers&rsquo; exemption from the other Levitical administrative duties reflects the Chronicler&rsquo;s elevation of temple music as primary, not supplementary, worship. They are day-and-night (<em>layl wᵉyômām ʿalêhem bᵉmᵉlāʾḵāh</em>) — the continuous nature of the singers&rsquo; service establishes the temple as a place of unceasing worship.</p>",
    "34": "<p>The closing summary formula for the Levitical leaders: <em>rāʾšê hāʾāḇôt lalwiyyîm lᵉtôlᵉdôtām rāʾšîm</em> — &lsquo;heads of the Levitical ancestral houses throughout their generations, leaders.&rsquo; The phrase <em>yāšᵉḇû bîrûšālāim</em> (&lsquo;they lived in Jerusalem&rsquo;) closes the settler list and serves as a geographical anchor — these Levitical institutions are Jerusalem-based, not provincial.</p>",
    "35": "<p>The Saul genealogy (vv35-44) is a near-verbatim repetition of 8:29-38, where it was the conclusion of the Benjaminite genealogy. Its reappearance here is a literary technique — the genealogy serves as a runway into the narrative of Saul&rsquo;s death in ch10. The founder of Gibeon, <em>yᵉʿîʾēl</em> (Jeiel), is introduced with his wife Maacah; Gibeon will be significant as the site of the tabernacle and high place in David&rsquo;s era (1 Chr 21:29; 2 Chr 1:3).</p>",
    "36": "<p>The sons of Jeiel/Gibeon: Abdon the firstborn, then five more names including Kish, Ner, and Nadab. The key names in this list are Ner (father of Abner, commander of Saul&rsquo;s army) and Kish (father of Saul — v39). The genealogy is working toward the explanation of Saul&rsquo;s lineage from the founder of Gibeon.</p>",
    "37": "<p>Four more sons: Gedor, Ahio, Zechariah, Mikloth. Ahio appears in 13:7 as one of the men guiding the cart carrying the ark — a member of the Gibeah community that has a role in the subsequent ark narrative. The name connections between genealogy and narrative are characteristic Chronicler technique.</p>",
    "38": "<p>Mikloth fathered Shimeam (<em>šimʾām</em>); the note that &lsquo;they also lived in Jerusalem across from their kinsmen&rsquo; (<em>wᵉhēm ʾap hēm negeḏ ʾaḥêhem yāšᵉḇû bîrûšālaim ʿim ʾaḥêhem</em>) indicates this Benjaminite branch maintained connection to the Jerusalem community alongside their Gibeah base — a feature that perhaps explains their survival through the Saul catastrophe.</p>",
    "39": "<p><strong><em>wᵉnēr hôlîd ʾet qîš wᵉqîš hôlîd ʾet šāʾûl</em></strong> — the genealogical chain reaches its destination: Ner → Kish → Saul. The Hiphil <em>hôlîd</em> (&lsquo;begat/fathered&rsquo;) is the standard genealogical verb. Saul&rsquo;s four sons are listed: Jonathan, Malchishua, Abinadab, and Eshbaal — note that <em>ʾeš bāʿal</em> (&lsquo;man of Baal&rsquo;) is the Chronicler&rsquo;s form; Samuel uses <em>îš bōšet</em> (&lsquo;man of shame,&rsquo; a polemical substitution for the Baal element). The Chronicler retains the original theophoric form without the Deuteronomistic bowdlerization.</p>",
    "40": "<p><strong><em>mᵉrîḇ bāʿal</em></strong> — Jonathan&rsquo;s son is called &lsquo;Meribbaal&rsquo; here; Samuel uses &lsquo;Mephibosheth.&rsquo; Both the Chronicler&rsquo;s form (<em>mᵉrîḇ</em>, &lsquo;the one who contends with Baal&rsquo; or &lsquo;Baal pleads&rsquo;) and Samuel&rsquo;s substitution (<em>mᵉpîḇōšet</em>, &lsquo;from the mouth of shame&rsquo;) preserve the theophoric element awkwardly — the Chronicler avoids the euphemism, consistent with his retention of Eshbaal in v39.</p>",
    "41": "<p>The sons of Micah son of Meribbaal: Pithon, Melech, and Tahrea — three names only; 1 Chr 8:35 adds a fourth (&lsquo;Ahaz&rsquo;) while 9:41 has three. This is a textual variant between the two versions of the same genealogy within Chronicles itself, suggesting the source documents had slightly different traditions. The Masoretes supply &lsquo;Ahaz&rsquo; in the margin but the BHS text of 9:41 lacks it.</p>",
    "42": "<p>The descent from Ahaz: <em>ʾāḥāz hôlîd ʾet yāʿrāh</em> — &lsquo;Ahaz fathered Jarah.&rsquo; Note the name <em>yāʿrāh</em> (Jarah) here versus <em>yehôʿaddāh</em> in 8:36 — another variant between the two genealogical forms, again pointing to divergent source traditions rather than authorial error. The chain Jarah → Alemeth, Azmaveth, Zimri → Moza continues the Saulide line past the dynasty&rsquo;s political death.</p>",
    "43": "<p>Moza fathered Binea; then <em>rᵉpāyāh</em> (Rephaiah) → <em>ʾelʿāsāh</em> (Eleasah) → <em>āṣēl</em> (Azel). The three-generation chain from Binea to Azel continues the Saulide genealogy six generations past Saul himself — into the post-exilic period, suggesting the Saulide line survived and was tracked by the Chronicler&rsquo;s sources even though it held no political power after David.</p>",
    "44": "<p>Azel&rsquo;s six sons conclude both the genealogy and chapter 9. The closing formula <em>ʾēlleh bᵉnê āṣēl</em> (&lsquo;these are the sons of Azel&rsquo;) mirrors the chapter&rsquo;s opening genealogical register. The Saulide line continues beyond the catastrophe narrated in ch10 — the genealogy provides the frame of survival around the narrative of death. Exactly the same list appears in 8:38.</p>"
  },
  "10": {
    "1": "<p><strong><em>wayyinnāgᵉpû yiśrāʾēl</em></strong> — &lsquo;And Israel was struck/defeated&rsquo; (Niphal of <em>nāgaph</em>). The Niphal passive frames Israel as the recipient of military calamity, not the agent — YHWH stands behind the defeat. <strong><em>wayyippᵉlû ḥᵃlālîm</em></strong> — &lsquo;falling as slain/pierced ones&rsquo; (<em>ḥālāl</em>, the slain in battle, often with connotations of dishonor). <strong><em>har haggîlbōaʿ</em></strong> — Mount Gilboa is the site; the Chronicler&rsquo;s version of the battle (parallel to 1 Sam 31) is briefer, omitting the prior night at Endor (1 Sam 28), because the Chronicler&rsquo;s purpose is the theological verdict in vv13-14, not the narrative details.</p>",
    "2": "<p><strong><em>wayyadbᵉqû pᵉlištîm</em></strong> — &lsquo;the Philistines pressed close after/clung to Saul&rsquo; (Qal imperfect of <em>dāḇaq</em>, usually used for covenant loyalty, as in Ruth 1:14 or Deut 4:4). The ironic use of <em>dāḇaq</em> for the enemy&rsquo;s pursuit — the word that describes righteous clinging to YHWH (Deut 10:20; 11:22) — is perhaps not intentional but sharpens the scene: Saul is overtaken by those who &lsquo;cling&rsquo; to him in violence. Jonathan, Abinadab, Malchishua — the three sons who die with their father.</p>",
    "3": "<p><strong><em>wattiḵbad hammiḥlāmāh ʾel šāʾûl</em></strong> — &lsquo;the battle pressed hard against Saul&rsquo; (literally &lsquo;was heavy&rsquo;; the idiom of <em>kāḇēḏ</em> for intensive or burdensome pressure). <strong><em>wayyimṣāʾûhû hammorîm</em></strong> — &lsquo;the archers found/overtook him.&rsquo; The root <em>māṣāʾ</em> (to find) used of the archers reaching Saul is suggestive: Saul has been &lsquo;found out,&rsquo; located in his moment of abandonment. <strong><em>wayyāḥel mēhammôrîm</em></strong> — &lsquo;and he was wounded by the archers&rsquo; (Qal imperfect of <em>ḥûl</em>, to writhe, be in anguish, or in this context to be wounded/pierced).</p>",
    "4": "<p><strong><em>hāʾărālîm hāʾēlleh</em></strong> — &lsquo;these uncircumcised ones.&rsquo; The word <em>ʿārēl</em> (uncircumcised) is the ethnic-covenantal boundary marker used throughout Samuel for Philistines as the quintessential covenant outsiders. Saul&rsquo;s fear is that they will <em>hitʿallᵉlû bô</em> — &lsquo;abuse/mock/make sport of him&rsquo; (Hithpael of <em>ʿālal</em>); the same verb is used of Israel&rsquo;s abuse by Egypt (Exod 10:2). <strong><em>wayyirrā mallʾōd</em></strong> — &lsquo;and he was very afraid&rsquo; (Qal imperfect of <em>yārēʾ</em>). The armor-bearer&rsquo;s refusal to kill the king (<em>lōʾ ʾāḇāh</em>, &lsquo;he was not willing&rsquo;) reflects the inviolability of the royal person — even in extremis, striking the anointed is unthinkable (cf. David&rsquo;s repeated refusals, 1 Sam 24:6; 26:9).</p>",
    "5": "<p>The armor-bearer fell on his own sword after Saul — the same word <em>wayyāmot</em> (&lsquo;and he died&rsquo;) for both, the king and his servant. The Chronicler&rsquo;s terse account omits the detail that Saul fell on his own sword first (1 Sam 31:4); the Chronicler says simply <em>wayyiqaḥ haḥereḇ wayyippōl ʿālêhā</em> — &lsquo;and he took the sword and fell upon it.&rsquo; The armor-bearer&rsquo;s identical death (<em>wayyāmot</em>) is noted without further comment — he followed his king in death as in service.</p>",
    "6": "<p><strong><em>wayyāmot šāʾûl ûšᵉlōšet bānāw</em></strong> — &lsquo;So Saul died, and his three sons died.&rsquo; The Chronicler adds <strong><em>wᵉkol bêtô yaḥdāw</em></strong> — &lsquo;and all his household together&rsquo; — a phrase not in 1 Sam 31:6, which says instead &lsquo;and all his men.&rsquo; The Chronicler&rsquo;s &lsquo;all his household&rsquo; underscores the totality of the dynastic collapse; it echoes the language of divine judgment against faithless houses in Kings (1 Kgs 21:22; 2 Kgs 9:8). The Meribbaal/Mephibosheth narrative is thus largely absent from Chronicles because the Chronicler has written the Saulide household as extinct — the ch9 genealogy preserving the line is presented as post-narratival continuation.</p>",
    "7": "<p><strong><em>wāyaʿazᵉḇû ʾet ʿārêhem wayyānusû</em></strong> — &lsquo;they abandoned their cities and fled.&rsquo; The verb <em>ʿāzaḇ</em> (to abandon, forsake) is significant: the same verb used of Israel&rsquo;s forsaking of YHWH (Deut 28:20; 1 Chr 28:9) is here applied to Israel&rsquo;s abandonment of their cities — the two abandonments are related in the Deuteronomistic-Chronicler theology. <strong><em>wayyāḇōʾû ḥaplištîm wayyēšᵉḇû bāhem</em></strong> — &lsquo;the Philistines came and settled in them&rsquo;; the invader&rsquo;s occupation of abandoned cities is the concrete embodiment of the covenant curse (Deut 28:30-33).</p>",
    "8": "<p><strong><em>lᵉpōšēṭ ḥᵃlālîm</em></strong> — &lsquo;to strip the slain&rsquo; (literally &lsquo;to strip those pierced/fallen&rsquo;). The stripping of fallen warriors for their weapons and valuables was standard ANE battlefield practice; the same act performed on Saul&rsquo;s body is a desecration because of his royal status. The Philistines &lsquo;found&rsquo; (<em>wayyimṣᵉʾû</em>) Saul and his sons — the same <em>māṣāʾ</em> (to find) as in v3, framing the entire battle sequence: the archers &lsquo;found&rsquo; Saul in the battle, the Philistines &lsquo;found&rsquo; his body on the field.</p>",
    "9": "<p><strong><em>wayYāsîrû ʾet rōʾšô</em></strong> — &lsquo;they stripped him, took his head.&rsquo; Decapitation of a fallen enemy was a trophy act with deep ANE symbolism (David took Goliath&rsquo;s head, 1 Sam 17:54). <strong><em>lᵉḇaśśēr ʾet ʿaṣabbêhem</em></strong> — &lsquo;to bring the good news (<em>bāśar</em>) to their idols (<em>ʿaṣabbêhem</em>).&rsquo; The word <em>ʿaṣāḇ</em> for idols is pejorative (the same root as &lsquo;pain/toil&rsquo; — Ps 16:4: &lsquo;those who run after another god multiply their sorrows [ʿaṣṣᵉḇōtām]&rsquo;). The irony is precise: the Philistines bring gospel-news (<em>bāśar</em>, the positive announcement) to objects of grief — the victory news delivered to pain-objects.</p>",
    "10": "<p><strong><em>bêt ʾĕlōhêhem</em></strong> — &lsquo;the house of their gods.&rsquo; The Chronicler places the armor in the general &lsquo;temple of their gods&rsquo; and Saul&rsquo;s head &lsquo;in the temple of Dagon&rsquo; (<em>bêt dāgôn</em>). 1 Sam 31:10 reverses the distribution — armor in &lsquo;the house of Ashtaroth,&rsquo; body fastened to the wall of Beth-shan. The Chronicler&rsquo;s focus on Dagon is theologically pointed: Dagon is the god before whom the captured ark humiliated itself (1 Sam 5:1-5), and now the Philistines hang Saul&rsquo;s head in Dagon&rsquo;s house — the same temple that will eventually bear witness to the ark&rsquo;s power. The theological juxtaposition is part of the Chronicler&rsquo;s consistent anti-idolatry polemic.</p>",
    "11": "<p><strong><em>wayyišmᵉʿû kol yōšᵉḇê yāḇêš gilʿāḏ</em></strong> — &lsquo;when all the inhabitants of Jabesh-gilead heard.&rsquo; The men of Jabesh-gilead have a special loyalty to Saul: he rescued them from Nahash the Ammonite at the beginning of his reign (1 Sam 11:1-11), and they repay that loyalty now. The Chronicler does not explain this bond — it is assumed the reader knows the backstory from Samuel.</p>",
    "12": "<p><strong><em>kol gibbôrê ḥāyil</em></strong> — &lsquo;all the valiant men&rsquo; — the same phrase used for capable priestly workers in 9:13. Here it describes the Jabesh-gilead warriors who make the night journey to retrieve Saul&rsquo;s body: <em>wayyiqqᵉḥû ʾet gūpat šāʾûl</em> — &lsquo;they took the corpse (<em>gûpāh</em>) of Saul.&rsquo; <strong><em>ûyqibrû ʾet ʿaṣmôtêhem</em></strong> — &lsquo;they buried their bones.&rsquo; The shift from &lsquo;bodies&rsquo; (1 Sam 31:12: <em>ʾet gᵉwiyyātō</em>) to &lsquo;bones&rsquo; in Chronicles may reflect a later stage (bones after burning/decomposition), or a textual variant. The oak at Jabesh (<em>hāʾēlāh</em>) serves as a funerary marker — trees as burial markers are attested in Gen 35:8 (Deborah buried under the &lsquo;oak of weeping&rsquo;).</p>",
    "13": "<p><strong><em>wayyāmot šāʾûl bᵉmaʿᵃlô</em></strong> — &lsquo;Saul died because of his unfaithfulness (<em>maʿal</em>).&rsquo; This is the Chronicler&rsquo;s unique contribution over 1 Samuel — the entire death narrative has been building to this theological verdict. <em>Māʿal</em> (unfaithfulness, covenant breach, treachery) is the Chronicler&rsquo;s signature evaluative term: it appears 24 times in Chronicles versus only 3 times in the parallel Samuel-Kings material. It denotes specifically the violation of the sacred, a betrayal of covenant with YHWH that carries corporate consequences. Three specific acts of <em>maʿal</em> are identified: (1) <strong><em>ʾăšer māʿal bîdbar YHWH</em></strong> — not keeping YHWH&rsquo;s command (the Amalekite disobedience, 1 Sam 15); (2) <strong><em>wᵉgam lišʾôl bāʾôḇ lîdrôš</em></strong> — consulting a medium to seek guidance (<em>dāraš</em>); and (3) implicitly from v14, failing to seek YHWH directly. The word <em>māʿal</em> brackets both the Saul death narrative and the exile summary of v1 (<em>bᵉmaʿalām</em>) — exile and royal death share the same root cause.</p>",
    "14": "<p><strong><em>wᵉlōʾ dāraš bîYHWH</em></strong> — &lsquo;and he did not seek YHWH&rsquo;s guidance.&rsquo; The verb <em>dāraš</em> (to seek, inquire, require) is the Chronicler&rsquo;s evaluative criterion for kings: those who <em>dāraš</em> YHWH are blessed (Asa, 2 Chr 14:4; Jehoshaphat, 17:3; Hezekiah, 31:21; Josiah, 34:3); those who do not are judged. Samuel-Kings uses the verb occasionally; the Chronicler systematizes it as the primary criterion of royal faithfulness. The specific charge here — Saul consulted a medium to seek (<em>dāraš</em>) guidance instead of seeking YHWH — places the medium consultation not merely as a ritual violation but as the misuse of the seeking-faculty itself. <strong><em>wayyᵉmîtēhû</em></strong> — &lsquo;therefore he [YHWH] put him to death&rsquo; — YHWH is the subject of Saul&rsquo;s death; the Philistines are the instrument but YHWH is the agent. <strong><em>wayYassēb ʾet hamᵉlûḵāh lᵉdāwid ben yišay</em></strong> — &lsquo;and turned the kingdom to David son of Jesse&rsquo; — the kingship transfer is divine action (<em>sāḇaḇ</em>, Hiphil, to turn/redirect), not merely political succession. The chapter ends not with Saul but with David — the dynasty toward which the Chronicler has been orienting the entire genealogical preface.</p>"
  }
}

def main():
    existing = load_comm('mkt-original', '1chronicles')
    merge_comm(existing, ORIGINAL)
    save_comm('mkt-original', '1chronicles', existing)
    v9 = len(ORIGINAL.get('9', {}))
    v10 = len(ORIGINAL.get('10', {}))
    print(f'1Chronicles 9-10 mkt-original written ({v9} + {v10} = {v9+v10} verses).')

if __name__ == '__main__':
    main()
